      | `InvalidVPCNetworkStateFault e ->
          `Assoc
            [("error", (`String "InvalidVPCNetworkStateFault"));
            ("details", (InvalidVPCNetworkStateFault.to_json e))]
      | `KMSKeyNotAccessibleFault e ->
          `Assoc
            [("error", (`String "KMSKeyNotAccessibleFault"));
            ("details", (KMSKeyNotAccessibleFault.to_json e))]
      | `NetworkTypeNotSupported e ->
          `Assoc
            [("error", (`String "NetworkTypeNotSupported"));
            ("details", (NetworkTypeNotSupported.to_json e))]
      | `OptionGroupNotFoundFault e ->
          `Assoc
            [("error", (`String "OptionGroupNotFoundFault"));
            ("details", (OptionGroupNotFoundFault.to_json e))]
      | `ProvisionedIopsNotAvailableInAZFault e ->
          `Assoc
            [("error", (`String "ProvisionedIopsNotAvailableInAZFault"));
            ("details", (ProvisionedIopsNotAvailableInAZFault.to_json e))]
      | `StorageQuotaExceededFault e ->
          `Assoc
            [("error", (`String "StorageQuotaExceededFault"));
            ("details", (StorageQuotaExceededFault.to_json e))]
      | `StorageTypeNotSupportedFault e ->
          `Assoc
            [("error", (`String "StorageTypeNotSupportedFault"));
            ("details", (StorageTypeNotSupportedFault.to_json e))]
      | `TenantDatabaseQuotaExceededFault e ->
          `Assoc
            [("error", (`String "TenantDatabaseQuotaExceededFault"));
            ("details", (TenantDatabaseQuotaExceededFault.to_json e))]
      | `VpcEncryptionControlViolationException e ->
          `Assoc
            [("error", (`String "VpcEncryptionControlViolationException"));
            ("details", (VpcEncryptionControlViolationException.to_json e))]
      | `Unknown_operation_error (code, msg) ->
          `Assoc (("error", (`String code)) ::
            ((match msg with
              | None -> []
              | Some m -> [("message", (`String m))])))
    let to_value t =
      let x = t.createDBInstanceReadReplicaResult in
      structure_to_wrapped_value
        [("DBInstance", (Option.map x.dBInstance ~f:DBInstance.to_value))]
        ~wrapper:"CreateDBInstanceReadReplicaResult"
        ~response:"ResponseMetaData"
    let to_query v = to_query to_value v
    let of_xml t =
      let xml_arg0 =
        Xml.child_exn ~context:context_ t "CreateDBInstanceReadReplicaResult" in
      let dBInstance =
        (Option.map ~f:DBInstance.of_xml) (Xml.child xml_arg0 "DBInstance") in
      make ?dBInstance ()
    let of_string s = of_xml (Awso.Xml.parse_response s)[@@warning "-32"]
    let of_json json__ =
      let dBInstance = field_map json__ "DBInstance" DBInstance.of_json in
      make ?dBInstance ()
    let to_json v = composed_to_json to_value v
  end[@@ocaml.doc
       "Creates a new DB instance that acts as a read replica for an existing source DB instance or Multi-AZ DB cluster. You can create a read replica for a DB instance running Db2, MariaDB, MySQL, Oracle, PostgreSQL, or SQL Server. You can create a read replica for a Multi-AZ DB cluster running MySQL or PostgreSQL. For more information, see Working with read replicas and Migrating from a Multi-AZ DB cluster to a DB instance using a read replica in the Amazon RDS User Guide. Amazon Aurora doesn't support this operation. To create a DB instance for an Aurora DB cluster, use the CreateDBInstance operation. RDS creates read replicas with backups disabled. All other attributes (including DB security groups and DB parameter groups) are inherited from the source DB instance or cluster, except as specified. Your source DB instance or cluster must have backup retention enabled."]
